@namespace sv_86897dde24fb45e099ddb8196fa3f840.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul class="nav nav-pills flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link text-start w-100 @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@namespace sv_86897dde24fb45e099ddb8196fa3f840.Components.Pages.Settings
@using sv_86897dde24fb45e099ddb8196fa3f840.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Profile Settings</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_profile is not null)
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="text-center">
                    <label class="form-label fw-semibold d-block">Avatar Preview</label>
                    <div class="avatar-preview mb-2">
                        @if (!string.IsNullOrWhiteSpace(_profile.AvatarUrl))
                        {
                            <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle" style="width:100px;height:100px;object-fit:cover;" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center text-white"
                                 style="width:100px;height:100px;font-size:2.5rem;margin:0 auto;">
                                @(_displayName?.Length > 0 ? _displayName[0].ToString().ToUpper() : "?")
                            </div>
                        }
                    </div>
                    <small class="text-muted text-break">@_profile.AvatarUrl</small>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
                Discard Changes
            </button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                @_successMessage
                <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
            </div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger alert-dismissible mt-3 fade show" role="alert">
                @_errorMessage
                <button type="button" class="btn-close" @onclick="() => _errorMessage = null"></button>
            </div>
        }
    }
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        _loading = true;
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields();
        _loading = false;
    }

    private void PopulateFields()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _bio = _profile.Bio;
    }

    private async Task SaveChanges()
    {
        if (_profile is null) return;
        _saving = true;
        _successMessage = null;
        _errorMessage = null;

        try
        {
            var updated = _profile with { DisplayName = _displayName, Email = _email, Bio = _bio };
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _successMessage = "Profile saved successfully!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save profile: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        PopulateFields();
        _successMessage = null;
        _errorMessage = null;
    }
}

