@namespace sv_86897dde24fb45e099ddb8196fa3f840.Components.Pages.Settings
@using sv_86897dde24fb45e099ddb8196fa3f840.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer" @onclick="() => _expanded = !_expanded">
        <h5 class="mb-0">Change Password</h5>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (LastPasswordChange.HasValue)
            {
                <p class="text-muted mb-3">
                    Last changed: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>

            @if (_message is not null)
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible mt-3 fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public DateTime? LastPasswordChange { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _isError;

    private async Task UpdatePassword()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;

        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

