+                <input type="password" class="form-control" @bind="_newPassword" />
+            </div>
+
+            <div class="mb-3">
+                <label class="form-label">Confirm New Password</label>
+                <input type="password" class="form-control" @bind="_confirmPassword" />
+            </div>
+
+            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@_saving">
+                @if (_saving)
+                {
+                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
+                }
+                Update Password
+            </button>
+
+            @if (_message is not null)
+            {
+                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible mt-3 fade show" role="alert">
