@namespace sv_86897dde24fb45e099ddb8196fa3f840.Components.Pages.Settings
@using sv_86897dde24fb45e099ddb8196fa3f840.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Security</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_settings is not null)
    {
        <ChangePasswordPanel LastPasswordChange="_settings.LastPasswordChange" />

        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h5 class="mb-1">Two-Factor Authentication</h5>
                        <span class="badge @(_settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_settings.TwoFactorEnabled" disabled
                               style="transform:scale(1.3);" />
                    </div>
                </div>
            </div>
        </div>

        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">Active Sessions</h5>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _settings.Sessions)
                            {
                                var isCurrent = session == _settings.Sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                                    <td class="text-end">
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevoke"
                             OnCancel="CancelRevoke" />

        @if (_revokeMessage is not null)
        {
            <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                @_revokeMessage
                <button type="button" class="btn-close" @onclick="() => _revokeMessage = null"></button>
            </div>
        }
    }
</div>

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;
    private string? _revokeMessage;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;

        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _revokeMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";

        _showRevokeDialog = false;
        _sessionToRevoke = null;

        // Reload sessions
        _settings = await SettingsService.GetSecuritySettingsAsync();
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@namespace sv_86897dde24fb45e099ddb8196fa3f840.Components.Pages.Settings
@using sv_86897dde24fb45e099ddb8196fa3f840.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Appearance</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5 class="mb-3">Theme</h5>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme.ToLower()}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5 class="mb-3">Font Size</h5>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size.ToLower()}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5 class="mb-3">Language</h5>
                    <select class="form-select" style="max-width:250px;" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                        @_successMessage
                        <button type="button" class="btn-close" @onclick="() => _successMessage = null"></button>
                    </div>
                }
            </div>

            <div class="col-md-5">
                <h5 class="mb-3">Live Preview</h5>
                <div class="border rounded p-3 @PreviewBgClass" style="@PreviewStyle">
                    <h6 style="@PreviewFontStyle">Sample Heading</h6>
                    <p class="@PreviewTextClass" style="@PreviewFontStyle">
                        This is how your content will look with the selected appearance settings.
                        The theme, font size, and compact mode are all reflected here.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mt-1" : "mt-3")">
                        <span class="badge @PreviewBadgeClass">Badge</span>
                        <button class="btn btn-sm @PreviewBtnClass" disabled>Button</button>
                    </div>
                    <hr />
                    <small class="@PreviewMutedClass" style="@PreviewFontStyle">
                        Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                    </small>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private bool IsDark => _theme == "Dark";
    private string PreviewBgClass => IsDark ? "bg-dark" : "bg-light";
    private string PreviewTextClass => IsDark ? "text-light" : "text-dark";
    private string PreviewMutedClass => IsDark ? "text-secondary" : "text-muted";
    private string PreviewBadgeClass => IsDark ? "bg-light text-dark" : "bg-dark text-light";
    private string PreviewBtnClass => IsDark ? "btn-outline-light" : "btn-outline-dark";

    private string PreviewStyle
    {
        get
        {
            var padding = _compactMode ? "padding:0.5rem;" : "padding:1rem;";
            return $"{padding}min-height:180px;transition:all 0.2s ease;";
        }
    }

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size:0.85rem;",
        "Large" => "font-size:1.15rem;",
        _ => "font-size:1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        _successMessage = null;

        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);

        _successMessage = "Appearance settings saved!";
        _saving = false;
    }
}

